import { Admin_home_View } from "../view/view.js";
import { Admin_home_Model } from "../model/model.js";

export class Admin_home_controller {
  constructor() {
    this.model = new Admin_home_Model();
    this.view = new Admin_home_View();

    this.model.registerListener((state) => {
      this.view.render_who_we_are_documents(state);
    });

    this.model.registerListener((state) => {
      this.view.render_edit_who_we_are_documents(state);
    });

    this.model.registerListener((state) => {
      this.view.render_edit_our_estates_text(state);
    });

    this.model.registerListener((state) => {
      this.view.render_edit_our_estates_images(state);
    });

    this.model.registerListener((state) => {
      this.view.render_edit_service_images(state);
    });

    this.view.articles_event_listener((index) => {
      if (index === 1) {
        this.model.fetch_who_we_are_documents();
      } else if (index === 2) {
        this.model.fetch_who_we_are_documents();
        this.view.edit_who_we_are_documents(this.edit_who_we_are_documents);
      } else if (index === 3) {
        this.model.fetch_our_estates_text();
        this.view.edit_our_estates_text(this.edit_our_estates_text);
      } else if (index === 4) {
        this.model.fetch_our_estates_images();
        this.view.edit_our_estates_images(this.edit_our_estates_images);
      } else if (index === 5) {
        this.model.fetch_service_images();
        this.view.edit_service_images(this.edit_service_images);
      }
    });
  }

  edit_who_we_are_documents = (
    old_document_name,
    new_document_name,
    pdf_document,
    a_tag_id,
  ) => {
    this.model.edit_who_we_are_documents(
      old_document_name,
      new_document_name,
      pdf_document,
      a_tag_id,
    );
  };

  edit_our_estates_text = (new_text) => {
    this.model.edit_our_estates_text(new_text);
  };

  edit_our_estates_images = (img, img_id) => {
    this.model.edit_our_estates_images(img, img_id);
  };

  edit_service_images = (img, img_id, img_old_name) => {
    this.model.edit_service_images(img, img_id, img_old_name);
  };
}
