    const success = document.getElementById(
      "edit_who_we_are_pdf_form_success_msg",
    );

    // Helper to hide everything
    const hideAll = () => {
      loading.style.display = "none";
      loading2.style.display = "none";
      success.style.display = "none";
      err.style.display = "none";
    };

    // 1️⃣ Loading
